+
+            group.bench_with_input(bench_id, &(&old, &new), |b, (old, new)| {
+                b.iter_custom(|iters| {
+                    let mut collector =
+                        FrameTimeCollector::new(&format!("xterm_like_{workload_name}_{w}x{h}"), w, h);
+                    let mut total = Duration::ZERO;
+
