+    fn remote_feed_replay_transcript_is_deterministic_for_identical_chunks() {
+        let chunks: [&[u8]; 5] = [b"ABCD", b"\x1b[2;3H", b"Z\x1b[5n", b"\x1b[6n\r\n", b"xy"];
+
+        let run_a = run_remote_feed_replay_fixture(&chunks);
